data   = json.loads(raw)
stats  = data["statistics"]
times  = [datetime.strptime(r["time"], "%Y-%m-%d %H:%M") for r in data["comparison"]]
stofs  = [r["stofs_m"]  for r in data["comparison"]]
obs    = [r["obs_m"]    for r in data["comparison"]]
errors = [r["error_m"]  for r in data["comparison"]]

# ── Plot ──────────────────────────────────────────────────────────────────────
fig, (ax1, ax2) = plt.subplots(2, 1, figsize=(12, 7), sharex=True,
                                gridspec_kw={"height_ratios": [3, 1], "hspace": 0.08})

# Panel 1 — Water levels
ax1.plot(times, obs,   color="#1f77b4", lw=1.8, label="CO-OPS Observed (NAVD88)")
ax1.plot(times, stofs, color="#2ca02c", lw=1.5, ls="--", label="STOFS-3D-Atlantic (NAVD88)")
ax1.set_ylabel("Water Level (m)", fontsize=11)
ax1.set_title(
    "STOFS-3D-Atlantic vs CO-OPS Observations\n"
    "Boston, MA — Station 8443970 | Cycle: 2026-02-18 12z",
    fontsize=12, fontweight="bold"
)
ax1.legend(loc="upper right", fontsize=10)
ax1.grid(True, alpha=0.35)
ax1.axhline(0, color="gray", lw=0.8, ls=":")

# Stats box
stats_text = (
    f"Bias:  {stats['bias']:+.3f} m\n"
    f"RMSE:  {stats['rmse']:.3f} m\n"
    f"MAE:   {stats['mae']:.3f} m\n"
    f"R:     {stats['correlation']:.4f}\n"
    f"N:     {stats['n']}"
)
ax1.text(0.015, 0.97, stats_text, transform=ax1.transAxes,
         fontsize=9, va="top", ha="left",
         bbox=dict(boxstyle="round,pad=0.4", facecolor="white", alpha=0.85, edgecolor="#cccccc"),
         fontfamily="monospace")

# Panel 2 — Error (all negative = constant under-forecast)
ax2.fill_between(times, errors, 0,
                 where=[e >= 0 for e in errors], color="#d62728", alpha=0.55, label="Over-forecast")
ax2.fill_between(times, errors, 0,
                 where=[e < 0  for e in errors], color="#1f77b4", alpha=0.55, label="Under-forecast")
ax2.axhline(0, color="black", lw=0.9)
# Extend y-axis to show the full error range
ax2.set_ylim(-0.60, 0.30)
ax2.set_ylabel("Error (m)", fontsize=11)
ax2.set_xlabel("Time (UTC)", fontsize=11)
ax2.legend(loc="lower left", fontsize=9)
ax2.grid(True, alpha=0.35)

# X-axis formatting
ax2.xaxis.set_major_formatter(mdates.DateFormatter("%b %d\n%H:%Mz"))
ax2.xaxis.set_major_locator(mdates.HourLocator(interval=3))
fig.autofmt_xdate(rotation=0, ha="center")

out = "/mnt/d/ocean-mcp/boston_stofs3d_validation.png"
plt.savefig(out, dpi=150, bbox_inches="tight")
print(f"Saved → {out}")
